import { useState } from "react";

export default function TodoApp() {
  const [text, setText] = useState("");
  const [todos, setTodos] = useState([]);

  function addTodo() {
    if (!text.trim()) return;

    setTodos([
      ...todos,
      {
        text,
        done: false,
      },
    ]);

    setText("");
  }

  function toggleDone(index) {
    setTodos(
      todos.map((todo, i) =>
        i === index
          ? { ...todo, done: !todo.done }
          : todo
      )
    );
  }

  function editTodo(index) {
    const newText = prompt("Edit todo", todos[index].text);

    if (!newText) return;

    setTodos(
      todos.map((todo, i) =>
        i === index
          ? { ...todo, text: newText }
          : todo
      )
    );
  }

  function deleteTodo(index) {
    setTodos(
      todos.filter((_, i) => i !== index)
    );
  }

  return (
    <main>
      <h1>📝 Todo</h1>

      <input
        value={text}
        onSubmit={e => setText(e.target.value)}
        placeholder="Task"
      />

      <ul>
        {todos.map((todo, i) => (
          <li key={i}>
            {todo.done
              ? <s>{todo.text}</s>
              : todo.text}

            {" "}

            <button onClick={() => toggleDone(i)}>
              {todo.done ? "Undo" : "Done"}
            </button>

            <button onClick={() => editTodo(i)}>
              Edit
            </button>

            <button onClick={() => deleteTodo(i)}>
              Delete
            </button>
          </li>
        ))}
      </ul>
    </main>
  );
}
